import{_ as a,o as r,c as n,a2 as l}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"绮春园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan/qichun-yuan.md","filePath":"landmarks/yuanmingyuan/qichun-yuan.md","lastUpdated":1784720050000}'),e={name:"landmarks/yuanmingyuan/qichun-yuan.md"};function o(i,t,s,u,h,g){return r(),n("div",null,[...t[0]||(t[0]=[l('<h1 id="绮春园" tabindex="-1">绮春园 <a class="header-anchor" href="#绮春园" aria-label="Permalink to &quot;绮春园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1753087457645-a4f6c7c64e39?w=1200&amp;q=80" alt="绮春园荷塘"></p><blockquote><p>&quot;绮春&quot;者，春色如绮。这里曾是太后太妃们的颐养之所，也是圆明园浩劫之后，唯一有古建筑幸存的地方。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>绮春园位于圆明三园东南部，是圆明园三园中成园最晚的一座。其地原为若干<strong>私家赐园</strong>（如大学士傅恒的赐园等），乾隆三十五年（1770年）前后陆续并入御园，定名&quot;绮春园&quot;；<strong>嘉庆年间大规模扩建</strong>，增建宫门与寝殿，成为皇太后、太妃们的居住颐养之地。</p><p>绮春园以水景见长，湖面曲折，荷塘连片，素有&quot;<strong>夏赏荷、秋观叶</strong>&quot;之美。更重要的是，园内的<strong>正觉寺</strong>是1860年英法联军焚园之后圆明园中<strong>唯一幸存的古建筑群</strong>——因它独立于园墙之外、驻有喇嘛看守，侥幸躲过了那场大火。</p><p>今天的绮春园区域是圆明园<strong>南门（正门）入口</strong>所在，绝大多数游客由此进园。正觉寺内如今设有马首回归展等陈列，是入园后的第一站看点。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>成园年代</strong></td><td style="text-align:left;">乾隆三十五年（1770年）前后并入御园，嘉庆年间扩建</td></tr><tr><td style="text-align:left;"><strong>历史功能</strong></td><td style="text-align:left;">皇太后、太妃颐养起居之所</td></tr><tr><td style="text-align:left;"><strong>核心看点</strong></td><td style="text-align:left;">正觉寺（唯一幸存古建筑）、马首回归展、荷塘</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">含在大门10元门票内；正觉寺展览免费</td></tr><tr><td style="text-align:left;"><strong>入口</strong></td><td style="text-align:left;">圆明园南门（绮春园宫门遗址附近），地铁4号线圆明园站最近</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="正觉寺" tabindex="-1">正觉寺 <a class="header-anchor" href="#正觉寺" aria-label="Permalink to &quot;正觉寺&quot;">​</a></h3><p>正觉寺位于绮春园西南部，始建于乾隆三十八年（1773年），是清代<strong>皇室喇嘛庙</strong>（藏传佛教寺院），供满洲、蒙古王公礼佛之用。寺院为汉式布局，中轴线依次有：</p><ul><li>山门、天王殿</li><li>三圣殿（正殿）</li><li>最上楼（二层佛楼）</li><li>左右配殿、文殊亭等</li></ul><p>1860年大火中，圆明园建筑几乎荡然无存，正觉寺因<strong>地处园外、独立成院</strong>而幸免于难，成为圆明园范围内唯一留存至今的古建筑群。2002年起经全面修缮，如今作为圆明园博物馆展厅使用，<strong>马首铜像</strong>即回归供奉于寺内文殊亭中。</p><h3 id="鉴碧亭与天心水面" tabindex="-1">鉴碧亭与天心水面 <a class="header-anchor" href="#鉴碧亭与天心水面" aria-label="Permalink to &quot;鉴碧亭与天心水面&quot;">​</a></h3><p>绮春园水网密布，荷塘众多，是圆明园最著名的<strong>赏荷佳处</strong>：</p><ul><li><strong>鉴碧亭</strong>：临水而建的方亭，取&quot;以水鉴碧&quot;之意，夏日凭栏可赏满池红莲</li><li><strong>天心水面</strong>：位于湖心位置的临水敞轩，&quot;天在心、水在面&quot;，是静观荷风月色的绝佳处</li><li><strong>凤麟洲</strong>：湖中小岛，形如凤麟，岛上有殿，为太后颐养之所</li></ul><p>每年6-8月，绮春园一带荷塘接天莲叶、映日荷花，是圆明园荷花节的中心展区。</p><h3 id="涵秋馆" tabindex="-1">涵秋馆 <a class="header-anchor" href="#涵秋馆" aria-label="Permalink to &quot;涵秋馆&quot;">​</a></h3><p><strong>涵秋馆</strong>位于绮春园西北部，取&quot;涵纳秋光&quot;之意，是清代帝后秋季游赏之所。馆区依山面水，秋日层林尽染时最为动人。如今遗址上仍可见基址与山形，秋来银杏黄、枫叶红，别有一番萧散之美。</p><h3 id="绮春园宫门" tabindex="-1">绮春园宫门 <a class="header-anchor" href="#绮春园宫门" aria-label="Permalink to &quot;绮春园宫门&quot;">​</a></h3><p>嘉庆扩建时增建的绮春园宫门，是太后驻跸时的正门，规制严整。如今的圆明园南门即设于绮春园区域，宫门遗址就在入口附近，入园时可留意遗址标识。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="太后们的-绮春岁月" tabindex="-1">太后们的&quot;绮春岁月&quot; <a class="header-anchor" href="#太后们的-绮春岁月" aria-label="Permalink to &quot;太后们的&quot;绮春岁月&quot;&quot;">​</a></h3><p>嘉庆朝以后，绮春园成为皇太后、太妃的颐养之地。道光年间，孝和睿皇后长期居此；咸丰朝的康慈皇贵太妃亦居绮春园。深宫妇人们在这座水木清华的园子里度过晚年——亭台之间，曾有多少无人知晓的宫廷往事。</p><p>1860年大火起时，园中内眷仓皇随咸丰帝北逃热河，此后再未归来。绮春园的太后时代，随那场大火一同终结。</p><h3 id="正觉寺的-幸存之谜" tabindex="-1">正觉寺的&quot;幸存之谜&quot; <a class="header-anchor" href="#正觉寺的-幸存之谜" aria-label="Permalink to &quot;正觉寺的&quot;幸存之谜&quot;&quot;">​</a></h3><p>为何满园皆焚，独正觉寺无恙？因正觉寺虽属圆明园范围，却<strong>筑有独立围墙、另设山门</strong>，且常年有喇嘛住持看守。英法联军焚掠集中于园内主体区域，这座偏居一隅的小寺被忽略，竟成圆明园地面古建筑的唯一孑遗。</p><p>今天站在正觉寺红墙之内，墙外是百年废墟，墙内是劫后梵宇——一墙之隔，恍若两个时代。2019年回归的马首铜像安奉于此，更让这座劫后寺院成为&quot;国宝回家&quot;的象征之地。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>正觉寺古建筑群</strong>：圆明园唯一幸存的清代建筑，红墙黄瓦与园中废墟形成强烈对比</li><li><strong>马首铜像回归展</strong>：寺内文殊亭，目前唯一回归圆明园本址的兽首真品</li><li><strong>绮春园荷塘</strong>：6-8月赏荷最佳处，鉴碧亭、天心水面均可凭栏观荷</li><li><strong>绮春园宫门遗址</strong>：嘉庆朝扩建的园门基址，可辨识当年的规制</li><li><strong>涵秋馆秋色</strong>：10月下旬至11月初，银杏与红枫交织的遗址秋景</li><li><strong>凤麟洲小岛</strong>：湖心岛影，昔日太后颐养之所的所在</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>绮春园区域紧邻圆明园<strong>南门</strong>（地铁4号线圆明园站最近入口），建议作为进园第一站</li><li>正觉寺（含马首展）随大门票入内即可；周一展览可能调整，行前可致电010-62543673确认</li><li><strong>赏荷季</strong>（6月中旬-8月中旬）清晨入园最佳，上午9点后游客渐多</li><li>游览路线建议：南门 → 正觉寺（马首展）→ 鉴碧亭 → 天心水面 → 三园交界 → 福海或西洋楼</li><li>园内荷花节期间设有摄影点，荷塘边请勿踩踏、采摘</li><li>正觉寺红墙是园内最佳拍照背景之一，建议避开人流高峰拍摄</li><li>绮春园与<a href="/beijing-travel-guide/landmarks/yuanmingyuan/fuhai.html">福海</a>、西洋楼同属南门入园后的顺路区域，一日可串联游完</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a>——三园全貌与游览路线</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/haiyan-tang.html">海晏堂与十二生肖兽首</a>——马首流失与回归的完整故事</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/fuhai.html">福海景区</a>——绮春园以西的最大湖面</li><li><a href="/beijing-travel-guide/history/yuanmingyuan-ruins.html">圆明园遗址历史专题</a>——1860年焚毁始末</li></ul><hr><p><strong>📍 位置</strong>：圆明三园东南部，圆明园南门入口区域 <strong>⏱️ 建议游览</strong>：1-1.5小时（含正觉寺与马首展） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a></p>',37)])])}const c=a(e,[["render",o]]);export{q as __pageData,c as default};
